const body = $input.all()[0].json.body || $input.all()[0].json;
const targetUrl = (body.target_url || '').replace(/\/+$/, '');
const apiKey    = body.api_key || '';
const entityId  = body.entity_id || 1;
const dryRun    = body.dry_run === true || body.dry_run === 'true';

if (!targetUrl) throw new Error('target_url is required');
if (!apiKey)    throw new Error('api_key is required');

return [{ json: { targetUrl, apiKey, entityId, dryRun, startedAt: new Date().toISOString() } }];

const { targetUrl, apiKey, entityId, dryRun } = $('Parse & Validate Input').all()[0].json;

const JOURNALS = [
  ['JV-SA','Sales Journal',        2],
  ['JV-PU','Purchase Journal',     3],
  ['JV-BK','Bank Journal',         4],
  ['JV-CS','Cash Journal',         5],
  ['JV-TX','Tax Journal',          1],
  ['JV-PY','Payroll Journal',      1],
  ['JV-FA','Fixed Assets Journal', 1],
  ['JV-MV','General Journal',      9],
  ['JV-FX','Forex Journal',        1],
];

const results = { created: 0, skipped: 0, errors: 0 };

if (!dryRun) {
  for (const [code, label, nature] of JOURNALS) {
    try {
      const check = await fetch(`${targetUrl}/api/index.php/accountingjournals?sqlfilters=(t.code:=:'${code}')`, {
        headers: { 'DOLAPIKEY': apiKey }
      });
      const existing = await check.json();
      if (Array.isArray(existing) && existing.length > 0) { results.skipped++; continue; }

      const post = await fetch(`${targetUrl}/api/index.php/accountingjournals`, {
        method: 'POST',
        headers: { 'DOLAPIKEY': apiKey, 'Content-Type': 'application/json' },
        body: JSON.stringify({ code, label, nature, entity: entityId, active: 1 })
      });
      const data = await post.json();
      typeof data === 'number' && data > 0 ? results.created++ : results.errors++;
    } catch(e) { results.errors++; }
  }
} else {
  results.skipped = JOURNALS.length;
}

return [{ json: { ...($('Parse & Validate Input').all()[0].json), journal_results: results } }];

const coaResults     = $('Seed Chart of Accounts').all()[0].json.coa_results;
const journalResults = $('Seed Journals').all()[0].json.journal_results;
const { targetUrl, dryRun, startedAt } = $('Parse & Validate Input').all()[0].json;

const completedAt = new Date().toISOString();
const durationMs  = new Date(completedAt) - new Date(startedAt);

const success = coaResults.errors === 0 && journalResults.errors === 0;

const report = [
  dryRun ? '🔍 *DRY RUN — b3Ɛq NG Deploy Report*' : (success ? '✅ *b3Ɛq NG Deploy Complete*' : '⚠️ *b3Ɛq NG Deploy Completed with Warnings*'),
  '',
  `🌐 Target: ${targetUrl}`,
  `⏱ Duration: ${(durationMs/1000).toFixed(1)}s`,
  '',
  `📊 Chart of Accounts:`,
  `   Created: ${coaResults.created}  |  Skipped: ${coaResults.skipped}  |  Errors: ${coaResults.errors}`,
  '',
  `📒 Journals:`,
  `   Created: ${journalResults.created}  |  Skipped: ${journalResults.skipped}  |  Errors: ${journalResults.errors}`,
  '',
  dryRun ? '→ Re-run with dry_run: false to execute' : '→ Activate module: Home → Setup → Modules → b3eqng',
  '→ SQL seed still required for VAT + WHT codes',
];

if (coaResults.log?.length > 0) {
  report.push('', '⚠ Errors:', ...coaResults.log.slice(0, 5));
}

return [{ json: {
  success,
  target: targetUrl,
  coa:     coaResults,
  journals: journalResults,
  duration_ms: durationMs,
  report_text: report.join('\n')
} }];
